import React from "react";
import "../HeaderBar/HeaderBar.css";
import { BrowserRouter as Link } from "react-router-dom";

export default function HeaderBar() {
  return (
    <>
      <BrowserRouter>
        <div className="headerBar">
          <Link to="/login"></Link>
        </div>
      </BrowserRouter>
    </>
  );
}
